  ('social-worker-moex-06241', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關平均數的特質，下列何者錯誤？', '["容易受到分配中所有分數精確值的影響", "各分數與平均數差的總和等於零", "非常容易受到極端分數的影響", "所有分數與平均數差的平方和是最大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
